mapper.select:
select e.*
from batch.workflow_edge e
left join batch.workflow_definition d on d.id = e.workflow_definition_id
where 1 = 1

    and e.workflow_definition_id = #{workflowDefinitionId}


    and d.tenant_id = #{tenantId}


    and d.workflow_code = #{workflowCode}


    and e.from_node_code = #{fromNodeCode}


    and e.to_node_code = #{toNodeCode}


    and e.edge_type = #{edgeType}


    and e.enabled = #{enabled}

order by e.id asc

    limit #{pageRequest.pageSize} offset (#{pageRequest.pageNo} - 1) * #{pageRequest.pageSize}

select count(1)
from batch.workflow_edge e
left join batch.workflow_definition d on d.id = e.workflow_definition_id
where 1 = 1

    and e.workflow_definition_id = #{workflowDefinitionId}


    and d.tenant_id = #{tenantId}


    and d.workflow_code = #{workflowCode}


    and e.from_node_code = #{fromNodeCode}


    and e.to_node_code = #{toNodeCode}


    and e.edge_type = #{edgeType}


    and e.enabled = #{enabled}

select *
from batch.workflow_edge
where workflow_definition_id = #{workflowDefinitionId}
  and from_node_code = #{fromNodeCode}
  and to_node_code = #{toNodeCode}
  and edge_type = #{edgeType}
limit 1
